sp_widget.client_script:
api.controller = function($rootScope, $scope, spUtil, $interval) {
    var c = this;

    c.data.exportFiles = c.data.exportFiles || [];
    c.data.historyRecords = c.data.historyRecords || [];

    c.activeTab = 'migration'; 
    c.switchTab = function(tabName) { c.activeTab = tabName; };

    $rootScope.$on('tracenow.needs_update', function() { c.server.update(); });
    $scope.$on('tracenow.queue_updated', function() {
        c.data.queueCount = $rootScope.tnQueue ? $rootScope.tnQueue.length : 0;
    });

    // --- POLLING LOGIC ---
    c.isRefreshingExports = false;
    c.refreshExports = function() {
        c.isRefreshingExports = true;
        c.server.get({ action: 'poll_exports' }).then(function(response) {
            if (response && response.data && response.data.exportFiles) {
                c.data.exportFiles = response.data.exportFiles;
            }
            setTimeout(function() {
                c.isRefreshingExports = false;
                $scope.$apply(); 
            }, 400); 
        });
    };

    var pollingPromise;
    c.startPolling = function() {
        if (angular.isDefined(pollingPromise)) return; 
        pollingPromise = $interval(function() {
            if (!c.data.exportFiles) return; 
            var isProcessing = c.data.exportFiles.some(function(file) {
                return file && file.status && file.status.toLowerCase() === 'processing';
            });

            if (isProcessing) {
                c.server.get({ action: 'poll_exports' }).then(function(response) {
                    if (response && response.data && response.data.exportFiles) {
                        c.data.exportFiles = response.data.exportFiles;
                    }
                });
            } else {
                c.stopPolling(); 
            }
        }, 1500); 
    };

    c.stopPolling = function() {
        if (angular.isDefined(pollingPromise)) {
            $interval.cancel(pollingPromise);
            pollingPromise = undefined;
        }
    };

    $scope.$watch('c.data.exportFiles', function(newVal) {
        if (!newVal || !Array.isArray(newVal)) return; 
        var isProcessing = newVal.some(function(file) {
            return file && file.status && file.status.toLowerCase() === 'processing';
        });
        if (isProcessing) c.startPolling();
    }, true);

    $scope.$on('$destroy', function() { c.stopPolling(); });

    c.cancelExport = function(jobId) {
        if (!confirm("Are you sure you want to cancel this export?")) return;
        c.server.get({ action: 'cancel_export', jobId: jobId }).then(function() {
            if (window.spUtil) spUtil.addInfoMessage("Export cancelled.");
            c.server.update(); 
        });
    };

    c.fetchingPage = false;
    c.changePage = function(newPage) {
        if (newPage < 1 || newPage > c.data.totalPages) return;
        c.fetchingPage = true;
        c.server.get({ action: 'fetch_history_page', page: newPage }).then(function(response) {
            if (response && response.data) {
                c.data.historyRecords = response.data.historyRecords || [];
                c.data.currentPage = response.data.currentPage;
                c.data.startIndex = response.data.startIndex;
                c.data.endIndex = response.data.endIndex;
            }
            c.fetchingPage = false;
        });
    };

    // --- THE GHOST ORIGIN IMPORT LOGIC ---
    c.importing = false;
    c.triggerImport = function() { document.getElementById('tracenow_dashboard_importer').click(); };

    $scope.handleFileSelect = function(event) {
        var fileInput = event.target;
        var file = fileInput.files[0];
        if (!file) return;

        if (file.name.indexOf('.xml') === -1) {
            if (window.spUtil) spUtil.addErrorMessage("Please select a valid .xml file.");
            fileInput.value = '';
            return;
        }

        c.importing = true;
        $scope.$apply(); 

        if (window.spUtil) spUtil.addInfoMessage("Initiating Ghost Origin upload. Bypassing scoped sandbox...");

        // Read the file locally FIRST to count the records
        var reader = new FileReader();
        reader.onload = function(e) {
            var xmlText = e.target.result;

            // Count the number of <sys_id> tags to get the exact record count
            var recordCount = (xmlText.match(/<sys_id>/g) || []).length;

            // 1. Create a stealth iframe that strips the Service Portal origin
            var iframeId = 'ghost_origin_iframe_' + Date.now();
            var iframe = document.createElement('iframe');
            iframe.id = iframeId;
            iframe.name = iframeId;
            iframe.style.display = 'none';
            iframe.referrerPolicy = 'no-referrer'; // THIS IS THE MAGIC KEY
            document.body.appendChild(iframe);

            // 2. Create a raw HTML form targeting the iframe
            var form = document.createElement('form');
            form.method = 'POST';
            form.action = '/sys_upload.do';
            form.enctype = 'multipart/form-data';
            form.target = iframeId;
            form.style.display = 'none';

            // 3. Add necessary system parameters (including the CSRF security token)
            var params = {
                'sysparm_target': 'sys_import',
                'sysparm_action': 'sys_import',
                'sysparm_ck': window.g_ck || ''
            };

            for (var key in params) {
                var input = document.createElement('input');
                input.type = 'hidden';
                input.name = key;
                input.value = params[key];
                form.appendChild(input);
            }

            // 4. Hijack the file input from the DOM so we don't lose the file object
            var parentNode = fileInput.parentNode;
            var nextSibling = fileInput.nextSibling;
            fileInput.name = 'sys_import'; // Change name to what the platform expects
            form.appendChild(fileInput);
            document.body.appendChild(form);

            // 5. Listen for the iframe to finish loading
            iframe.onload = function() {
                c.importing = false;

                // Restore the file input back to the widget UI
                fileInput.value = '';
                fileInput.name = ''; 
                if (nextSibling) {
                    parentNode.insertBefore(fileInput, nextSibling);
                } else {
                    parentNode.appendChild(fileInput);
                }

                // Destroy the evidence
                form.remove();
                iframe.remove();

                if (window.spUtil && spUtil.clearMessages) spUtil.clearMessages();

                // Display the dynamic success message!
                alert("✅ Successfully imported " + recordCount + " records."); 
                c.server.update(); 
                $scope.$apply(); 
            };

            // 6. Fire the payload natively
            form.submit();
        };

        // Trigger the FileReader to start reading the XML file
        reader.readAsText(file);
    };
};

sp_widget.css:
.tn-dashboard {
  font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif;
}

/* Hero Section */
.tn-hero {
  background-color: #dbeafe;
  border-radius: 12px;
  padding: 40px;
  margin-bottom: 24px;
}

.tn-badge {
  display: inline-block;
  background-color: #ffffff;
  padding: 6px 14px;
  border-radius: 20px;
  font-size: 12px;
  font-weight: 600;
  color: #334155;
  margin-bottom: 20px;
  box-shadow: 0 1px 2px rgba(0,0,0,0.05);
}

.tn-star { color: #eab308; margin-right: 6px; }

.tn-title {
  font-size: 28px;
  font-weight: 700;
  color: #0f172a;
  margin: 0 0 16px 0;
}

.tn-desc {
  font-size: 15px;
  color: #475569;
  max-width: 650px;
  line-height: 1.5;
  margin: 0 0 24px 0;
}

.tn-btn-primary {
  background-color: #1d4ed8;
  color: white;
  border: none;
  padding: 10px 24px;
  border-radius: 6px;
  font-size: 14px;
  font-weight: 600;
  cursor: pointer;
  transition: background-color 0.2s;
}

.tn-btn-primary:hover { background-color: #1e40af; }

/* Stats Container */
.tn-stats-container {
  display: flex;
  gap: 20px;
  flex-wrap: wrap;
}

.tn-stat-card {
  flex: 1;
  min-width: 200px;
  background: #ffffff;
  border: 1px solid #e2e8f0;
  border-radius: 12px;
  padding: 20px;
  box-shadow: 0 4px 6px -1px rgba(0,0,0,0.05);
}

.tn-stat-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  margin-bottom: 16px;
}

.tn-stat-label {
  font-size: 13px;
  font-weight: 600;
  color: #64748b;
}

.tn-icon-wrapper {
  width: 32px;
  height: 32px;
  border-radius: 8px;
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 14px;
}

/* Specific Icon Colors */
.tn-icon-blue { background: #e0f2fe; color: #0284c7; }
.tn-icon-green { background: #dcfce7; color: #16a34a; }
.tn-icon-purple { background: #f3e8ff; color: #9333ea; }
.tn-icon-orange { background: #ffedd5; color: #ea580c; }

.tn-stat-value {
  font-size: 32px;
  font-weight: 700;
  color: #0f172a;
  margin-bottom: 4px;
}

.tn-stat-subtext {
  font-size: 12px;
  color: #94a3b8;
  font-weight: 500;
}

/* Tab System */
.tn-tabs-container {
  display: flex;
  border-bottom: 1px solid #e2e8f0;
  background-color: #f8fafc;
}

.tn-tab {
  padding: 16px 24px;
  font-weight: 600;
  font-size: 15px;
  cursor: pointer;
  transition: all 0.2s ease-in-out;
  color: #64748b;
  border-bottom: 2px solid transparent;
}

.tn-tab.active {
  color: #0f172a;
  background: #ffffff;
  border-bottom: 2px solid #6366f1;
}

.tn-tab:hover:not(.active) {
  color: #334155;
  background-color: #f1f5f9;
}

/* Custom UI Elements (Buttons & Progress) */
.tn-btn-download {
  background: #10b981;
  color: white;
  padding: 6px 12px;
  border-radius: 4px;
  text-decoration: none;
  font-weight: 600;
  font-size: 13px;
  display: inline-block;
  transition: background 0.2s;
}

.tn-btn-download:hover { background: #059669; color: white; text-decoration: none; }

.tn-progress-bg {
  margin-top: 6px;
  width: 100%;
  background-color: #e2e8f0;
  border-radius: 4px;
  height: 6px;
  overflow: hidden;
}

.tn-progress-fill {
  height: 100%;
  background-color: #3b82f6;
  transition: width 0.4s ease;
}

sp_widget.script:
(function() {
    data.exportFiles = [];
    data.historyRecords = [];
    data.queueCount = 0;
    data.migratedCount = 0;
    data.recentRuns = 0;
    data.successRate = 0;

    // --- 1. SMART POLLING ---
    if (input && input.action === 'poll_exports') {
        // Changed to standard GlideRecord to prevent ACL blocking
        var grPoll = new GlideRecord('x_1862238_tracenow_export_job');
        grPoll.orderByDesc('sys_created_on');
        grPoll.setLimit(10);
        grPoll.query();

        var nowMsPoll = new GlideDateTime().getNumericValue();

        while(grPoll.next()) {
            var pAttGr = new GlideRecord('sys_attachment');
            pAttGr.addQuery('table_sys_id', grPoll.getUniqueValue());
            pAttGr.query();
            var pAttId = '';
            if (pAttGr.next()) pAttId = pAttGr.getUniqueValue();

            // Status check reads both standard fields
            var pStatus = grPoll.getValue('status') || grPoll.getValue('state') || 'Pending';
            var pPct = parseInt(grPoll.getValue('percent_complete') || 0, 10);

            var pEtaText = "";
            if (pStatus.toLowerCase() === 'processing') {
                var pCreatedStr = grPoll.getValue('sys_created_on');
                if (pCreatedStr) {
                    var pCreatedMs = new GlideDateTime(pCreatedStr).getNumericValue();
                    if (pPct > 0 && pPct < 100) {
                        var elapsedMs = nowMsPoll - pCreatedMs;
                        if (elapsedMs < 0) elapsedMs = 1000;
                        var totalEstMs = (elapsedMs / pPct) * 100;
                        var remainMs = totalEstMs - elapsedMs;
                        var remainSec = Math.round(remainMs / 1000);
                        pEtaText = remainSec > 60 ? "~" + Math.ceil(remainSec / 60) + "m remaining" : "~" + Math.max(1, remainSec) + "s remaining";
                    } else {
                        pEtaText = "Estimating...";
                    }
                }
            }

            data.exportFiles.push({
                sys_id: grPoll.getUniqueValue(),
                record_number: grPoll.getValue('record_number') || '-',
                table: grPoll.getValue('table_name') || '-',
                status: pStatus,
                percent: pPct,
                created_on: grPoll.getValue('sys_created_on'),
                eta_text: pEtaText,
                attachment_id: pAttId
            });
        }
        return; 
    }

    // --- 2. CANCEL EXPORT ---
    if (input && input.action === 'cancel_export' && input.jobId) {
        var cancelGr = new GlideRecord('x_1862238_tracenow_export_job');
        if (cancelGr.get(input.jobId)) {
            cancelGr.setValue('status', 'Cancelled');
            cancelGr.update();
        }
    }

    // --- 3. IMPORT XML ---
    if (input && input.action === 'import_xml') {
        try {
            // Correctly calling the scoped script include
            var importer = new x_1862238_tracenow.dm_import();
            var results = importer.processXML(input.xmlPayload);
            data.importError = results.error;
            data.importCount = results.count;
        } catch (e) {
            // Improved error logging to catch the exact failure
            data.importError = "Engine Error: " + (e.message || String(e));
            gs.error("TraceNow Import Error: " + e.message);
        }
        return; 
    }

    // --- 4. MIGRATION HISTORY ---
    var pageIndex = (input && input.page) ? parseInt(input.page, 10) : 1;
    var recordsPerPage = 10;
    var offsetStart = (pageIndex - 1) * recordsPerPage;
    var offsetEnd = offsetStart + recordsPerPage;

    var grCount = new GlideAggregate('x_1862238_tracenow_migration_history');
    grCount.addAggregate('COUNT');
    grCount.query();
    var totalRows = 0;
    if (grCount.next()) totalRows = parseInt(grCount.getAggregate('COUNT'), 10);

    data.totalRecords = totalRows;
    data.totalPages = Math.ceil(totalRows / recordsPerPage) || 1;
    data.currentPage = pageIndex;

    // Changed to standard GlideRecord
    var grHistoryList = new GlideRecord('x_1862238_tracenow_migration_history');
    grHistoryList.orderByDesc('sys_created_on');
    grHistoryList.chooseWindow(offsetStart, offsetEnd);
    grHistoryList.query();

    while (grHistoryList.next()) {
        data.historyRecords.push({
            sys_id: grHistoryList.getUniqueValue(),
            record_number: grHistoryList.getValue('record_number') || '-',
            target_record_number: grHistoryList.getValue('target_record_number') || '-',
            table: grHistoryList.getValue('table_name') || grHistoryList.getValue('table') || 'Migration Process',
            status: grHistoryList.getValue('status') || grHistoryList.getValue('state') || 'Unknown',
            created_on: grHistoryList.getValue('sys_created_on'),
            user: grHistoryList.getValue('sys_created_by') || 'system'
        });
    }

    data.startIndex = totalRows > 0 ? (offsetStart + 1) : 0;
    data.endIndex = offsetStart + data.historyRecords.length;

    if (input && input.action === 'fetch_history_page') return; 

    // --- 5. STATS ---
    var grQueue = new GlideRecord('x_1862238_tracenow_migration_queue');
    if (grQueue.isValid()) {
        grQueue.query();
        data.queueCount = grQueue.getRowCount();
    }

    var successCount = 0;
    var failedCount = 0;
    var grHistoryStats = new GlideRecord('x_1862238_tracenow_migration_history');
    if (grHistoryStats.isValid()) {
        grHistoryStats.query();
        while (grHistoryStats.next()) {
            var statusVal = (grHistoryStats.getValue('status') || grHistoryStats.getValue('state') || '').toString().toLowerCase();
            if (statusVal === 'success') successCount++;
            else if (statusVal === 'failed') failedCount++;
        }
        data.migratedCount = successCount;
        var totalProcessed = successCount + failedCount;
        if (totalProcessed > 0) data.successRate = Math.round((successCount / totalProcessed) * 100);
    }

    var grRecent = new GlideRecord('x_1862238_tracenow_migration_history');
    if (grRecent.isValid()) {
        grRecent.addEncodedQuery('sys_created_onONLast 7 days@javascript:gs.beginningOfLast7Days()@javascript:gs.endOfLast7Days()');
        grRecent.query();
        data.recentRuns = grRecent.getRowCount();
    }

    // --- 6. INITIAL EXPORT LOAD ---
    // Changed to standard GlideRecord
    var grExpInit = new GlideRecord('x_1862238_tracenow_export_job');
    grExpInit.orderByDesc('sys_created_on');
    grExpInit.setLimit(10);
    grExpInit.query();

    var nowMsInit = new GlideDateTime().getNumericValue();

    while(grExpInit.next()) {
        var attGrInit = new GlideRecord('sys_attachment');
        attGrInit.addQuery('table_sys_id', grExpInit.getUniqueValue());
        attGrInit.query();
        var attIdInit = '';
        if (attGrInit.next()) attIdInit = attGrInit.getUniqueValue();

        // Status check reads both standard fields
        var statusInit = grExpInit.getValue('status') || grExpInit.getValue('state') || 'Pending';
        var pctInit = parseInt(grExpInit.getValue('percent_complete') || 0, 10);

        var etaTextInit = "";
        if (statusInit.toLowerCase() === 'processing') {
            var createdStrInit = grExpInit.getValue('sys_created_on');
            if (createdStrInit) {
                var createdMsInit = new GlideDateTime(createdStrInit).getNumericValue();
                if (pctInit > 0 && pctInit < 100) {
                    var elapsedMsInit = nowMsInit - createdMsInit;
                    if (elapsedMsInit < 0) elapsedMsInit = 1000;
                    var totalEstMsInit = (elapsedMsInit / pctInit) * 100;
                    var remainMsInit = totalEstMsInit - elapsedMsInit;
                    var remainSecInit = Math.round(remainMsInit / 1000);
                    etaTextInit = remainSecInit > 60 ? "~" + Math.ceil(remainSecInit / 60) + "m remaining" : "~" + Math.max(1, remainSecInit) + "s remaining";
                } else {
                    etaTextInit = "Estimating...";
                }
            }
        }

        data.exportFiles.push({
            sys_id: grExpInit.getUniqueValue(),
            record_number: grExpInit.getValue('record_number') || '-',
            table: grExpInit.getValue('table_name') || '-',
            status: statusInit,
            percent: pctInit,
            created_on: grExpInit.getValue('sys_created_on'),
            eta_text: etaTextInit,
            attachment_id: attIdInit
        });
    }
})();
